    16  UserMap readHtpasswd(const std::string& htpasswd) {
    17    UserMap users;
    18
    19    std::istringstream htpsswd_ss(htpasswd);
    20    std::string line;
    21
    22    while (std::getline(htpsswd_ss, line)) {
    23      // TODO(wbpcode): should we trim the spaces or empty chars?
    24
    25      // Skip empty lines and comments.
    26      if (line.empty() || line[0] == '#') {
    27        continue;
    28      }
    29
    30      const size_t colon_pos = line.find(':');
    31      if (colon_pos == std::string::npos) {
    32        throw EnvoyException("basic auth: invalid htpasswd format, username:password is expected");
    33      }
    34
    35      std::string name = line.substr(0, colon_pos);
    36      std::string hash = line.substr(colon_pos + 1);
    37
    38      if (name.empty() || hash.empty()) {
    39        throw EnvoyException("basic auth: empty user name or password");
    40      }
    41
    42      if (users.contains(name)) {
    43        throw EnvoyException("basic auth: duplicate users");
    44      }
    45
    46      if (!absl::StartsWith(hash, "{SHA}")) {
    47        throw EnvoyException("basic auth: unsupported htpasswd format: please use {SHA}");
    48      }
    49
    50      hash = hash.substr(5);
    51      // The base64 encoded SHA1 hash is 28 bytes long
    52      if (hash.length() != 28) {
    53        throw EnvoyException("basic auth: invalid htpasswd format, invalid SHA hash length");
    54      }
    55
    56      users.insert({name, {name, hash}});
    57    }
    58
    59    return users;
    60  }
